import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import io from 'socket.io-client';
import './ChatBot.css';

const ChatBot = () => {
  const { user, isAuthenticated } = useAuth();
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [agents, setAgents] = useState([]);
  const [selectedAgent, setSelectedAgent] = useState(null);
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    // Initialize socket
    initializeSocket();

    // Show welcome messages
    if (showWelcome) {
      setTimeout(() => {
        setMessages([
          {
            _id: 'welcome-1',
            message: "👋 Welcome to Real Estate! How can we help you today?",
            sender: { name: 'Bot', _id: 'bot' },
            createdAt: new Date(),
            isBot: true
          },
          {
            _id: 'welcome-2',
            message: "I can help you find your dream property or connect you with our expert agents!",
            sender: { name: 'Bot', _id: 'bot' },
            createdAt: new Date(),
            isBot: true
          }
        ]);
      }, 500);
    }

    if (isAuthenticated) {
      fetchAgents();
    }

    return () => {
      if (socket) {
        socket.disconnect();
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isAuthenticated]);

  useEffect(() => {
    if (selectedAgent && user) {
      loadChatHistory();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedAgent]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const initializeSocket = () => {
    const newSocket = io('http://localhost:5000');
    setSocket(newSocket);

    newSocket.on('connect', () => {
      setIsConnected(true);
    });

    newSocket.on('disconnect', () => {
      setIsConnected(false);
    });

    newSocket.on('receive-message', (data) => {
      setMessages(prev => [...prev, {
        _id: Date.now(),
        message: data.message,
        sender: data.sender,
        createdAt: new Date(data.timestamp)
      }]);
    });
  };

  const fetchAgents = async () => {
    try {
      const response = await API.get('/users?role=agent');
      setAgents(response.data.data);
      if (response.data.data.length > 0 && !selectedAgent) {
        setSelectedAgent(response.data.data[0]);
      }
    } catch (error) {
      console.error('Error fetching agents:', error);
    }
  };

  const loadChatHistory = async () => {
    try {
      setShowWelcome(false);
      const response = await API.get(`/chat/${selectedAgent._id}`);
      
      if (response.data.data.length === 0) {
        // If no history, show agent intro
        setMessages([
          {
            _id: 'intro',
            message: `Hi! I'm ${selectedAgent.name}, your dedicated agent. How can I help you find your perfect property?`,
            sender: selectedAgent,
            createdAt: new Date(),
            isBot: true
          }
        ]);
      } else {
        setMessages(response.data.data);
      }
    } catch (error) {
      console.error('Error loading chat history:', error);
      setMessages([]);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim()) return;

    if (!isAuthenticated) {
      alert('Please login to chat with agents!');
      return;
    }

    if (!selectedAgent) {
      alert('Please wait while we connect you to an agent...');
      return;
    }

    const tempMessage = {
      _id: Date.now(),
      message: inputMessage,
      sender: user,
      createdAt: new Date()
    };

    // Add message immediately for better UX
    setMessages(prev => [...prev, tempMessage]);
    setInputMessage('');

    try {
      // Save to database
      await API.post('/chat/send', {
        receiver: selectedAgent._id,
        message: inputMessage
      });

      // Send via Socket.io
      if (socket && isConnected) {
        socket.emit('send-message', {
          roomId: `user-${selectedAgent._id}`,
          message: inputMessage,
          sender: user,
          timestamp: new Date()
        });
      }
    } catch (error) {
      console.error('Error sending message:', error);
      alert('Failed to send message. Please try again.');
      // Remove failed message
      setMessages(prev => prev.filter(m => m._id !== tempMessage._id));
      setInputMessage(inputMessage); // Restore input
    }
  };

  const quickReplies = [
    "I'm looking for a property",
    "Schedule a viewing",
    "Ask about financing",
    "Speak to an agent"
  ];

  const handleQuickReply = (reply) => {
    setInputMessage(reply);
  };

  if (!isAuthenticated) {
    return (
      <>
        <div className="chat-toggle" onClick={() => alert('Please login to chat with our agents!')}>
          <div className="toggle-icon">💬</div>
          <div className="notification-badge">
            <span className="pulse-dot"></span>
          </div>
        </div>
      </>
    );
  }

  return (
    <>
      {/* Chat Toggle Button */}
      <div className={`chat-toggle ${isOpen ? 'active' : ''}`} onClick={() => setIsOpen(!isOpen)}>
        <div className="toggle-icon">
          {isOpen ? '✕' : '💬'}
        </div>
        {!isOpen && (
          <div className="notification-badge">
            <span className="pulse-dot"></span>
          </div>
        )}
      </div>

      {/* Chat Window */}
      <div className={`chat-window ${isOpen ? 'open' : ''}`}>
        {/* Chat Header */}
        <div className="chat-header">
          <div className="chat-header-content">
            <div className="agent-avatar-chat">
              <span>👨‍💼</span>
              <div className={`status-dot ${isConnected ? 'online' : 'offline'}`}></div>
            </div>
            <div className="agent-info-chat">
              <h4>{selectedAgent?.name || 'Real Estate Support'}</h4>
              <p className="status-text">{isConnected ? '🟢 Online' : '🔴 Connecting...'}</p>
            </div>
          </div>
          <button className="chat-close" onClick={() => setIsOpen(false)}>
            ✕
          </button>
        </div>

        {/* Agent Selection */}
        {agents.length > 1 && (
          <div className="agent-selector">
            <label>Chat with:</label>
            <select 
              value={selectedAgent?._id || ''} 
              onChange={(e) => {
                const agent = agents.find(a => a._id === e.target.value);
                setSelectedAgent(agent);
              }}
              className="agent-select"
            >
              {agents.map(agent => (
                <option key={agent._id} value={agent._id}>
                  {agent.name}
                </option>
              ))}
            </select>
          </div>
        )}

        {/* Messages Area */}
        <div className="chat-messages">
          {messages.map((msg, index) => (
            <div 
              key={msg._id || index} 
              className={`message ${msg.sender._id === user._id ? 'own' : 'other'}`}
            >
              {msg.sender._id !== user._id && (
                <div className="message-avatar">
                  {msg.isBot ? '🤖' : '👨‍💼'}
                </div>
              )}
              <div className="message-content">
                {msg.sender._id !== user._id && (
                  <div className="message-sender">{msg.sender.name}</div>
                )}
                <div className="message-bubble">
                  {msg.message}
                </div>
                <div className="message-time">
                  {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>

        {/* Quick Replies - Show when few messages */}
        {messages.length <= 3 && (
          <div className="quick-replies">
            {quickReplies.map((reply, index) => (
              <button
                key={index}
                className="quick-reply-btn"
                onClick={() => handleQuickReply(reply)}
              >
                {reply}
              </button>
            ))}
          </div>
        )}

        {/* Input Area */}
        <form className="chat-input-area" onSubmit={handleSendMessage}>
          <input
            type="text"
            value={inputMessage}
            onChange={(e) => setInputMessage(e.target.value)}
            placeholder="Type your message..."
            className="chat-input"
          />
          <button 
            type="submit" 
            className="chat-send-btn"
            disabled={!inputMessage.trim()}
          >
            <span className="send-icon">📤</span>
          </button>
        </form>
      </div>
    </>
  );
};

export default ChatBot;
